#include <bits/stdc++.h>
#define int long long
using namespace std;
int n, t;
int ans;
int h[100005];
signed main() {
	cin >> n >> t;
	t <<= 1;
	for (int i = 1; i < n; i++) {
		cin >> h[i];
	}
	for (int i = 1, j = 0, sum = 0; i < n; i++) {
		while (j < n && sum < t) {
			sum += h[++j];
		}
		ans = max (ans, j - i + 1);
		sum -= h[i];
	}
	cout << ans;
	return 0;
}
